 1	import React, { FC } from 'react';
 2	
 3	import PendingChangesBreadcrumb from '@kubevirt-utils/components/PendingChanges/PendingChangesBreadcrumb/PendingChangesBreadcrumb';
 4	import { getPendingChangesByTab } from '@kubevirt-utils/components/PendingChanges/utils/helpers';
 5	import { PendingChange } from '@kubevirt-utils/components/PendingChanges/utils/types';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { List } from '@patternfly/react-core';
 8	
 9	type LiveMigratePendingChangesProps = {
10	  pendingChanges: PendingChange[];
11	};
12	
13	const LiveMigratePendingChanges: FC<LiveMigratePendingChangesProps> = ({ pendingChanges }) => {
14	  const { t } = useKubevirtTranslation();
15	
16	  const { pendingChangesNICsTab } = getPendingChangesByTab(pendingChanges);
17	
18	  return (
19	    <>
20	      {t(
21	        'The following areas have pending changes that will be applied when this VirtualMachine is live migrated or restarted.',
22	      )}
23	      <List>
24	        <PendingChangesBreadcrumb pendingChanges={pendingChangesNICsTab} />
25	      </List>
26	    </>
27	  );
28	};
29	
30	export default LiveMigratePendingChanges;

