 1	import * as React from 'react';
 2	
 3	import { isEmpty } from '@kubevirt-utils/utils/utils';
 4	import { Breadcrumb, BreadcrumbHeading, BreadcrumbItem, ListItem } from '@patternfly/react-core';
 5	
 6	import { PendingChange } from '../utils/types';
 7	
 8	type PendingChangesBreadcrumbProps = {
 9	  pendingChanges: PendingChange[];
10	};
11	
12	const PendingChangesBreadcrumb: React.FC<PendingChangesBreadcrumbProps> = ({ pendingChanges }) => {
13	  if (isEmpty(pendingChanges)) {
14	    return null;
15	  }
16	
17	  return (
18	    <ListItem>
19	      <Breadcrumb>
20	        <BreadcrumbHeading>{pendingChanges?.[0]?.tabLabel}</BreadcrumbHeading>
21	        <BreadcrumbItem style={{ marginTop: 0 }}>
22	          {pendingChanges?.map(({ handleAction, label }, index) => (
23	            <>
24	              {index !== 0 && <div style={{ marginRight: '8px' }}>,</div>}
25	              <a key={label} onClick={handleAction}>
26	                {label}
27	              </a>
28	            </>
29	          ))}
30	        </BreadcrumbItem>
31	      </Breadcrumb>
32	    </ListItem>
33	  );
34	};
35	
36	export default PendingChangesBreadcrumb;

